# Write-CanonFiles7.ps1 — Creates D1.6 discovery scripts for all 3 specs
# Run from: C:\Users\whale\git\uiao\tools\
# Usage:    powershell -ExecutionPolicy Bypass -File .\Write-CanonFiles7.ps1

$ErrorActionPreference = "Stop"
$repoRoot = "C:\Users\whale\git\uiao"

if (-not (Test-Path $repoRoot)) {
    Write-Error "Repo root not found: $repoRoot"
    return
}

$discoveryDir = Join-Path $repoRoot "tools\discovery"
if (-not (Test-Path $discoveryDir)) {
    New-Item -Path $discoveryDir -ItemType Directory -Force | Out-Null
}

# --- Spec 1 D1.6 — BitLocker & LAPS State Assessment ---
$b64_0 = ""

$outFile0 = Join-Path $discoveryDir "Spec1-D1.6-Get-BitLockerLAPSStateAssessment.ps1"
$bytes0 = [System.Convert]::FromBase64String($b64_0)
[System.IO.File]::WriteAllBytes($outFile0, $bytes0)
Write-Host "  OK  $outFile0" -ForegroundColor Green

# --- Spec 2 D1.6 — Worker Type Taxonomy ---
$b64_1 = ""

$outFile1 = Join-Path $discoveryDir "Spec2-D1.6-New-WorkerTypeTaxonomy.ps1"
$bytes1 = [System.Convert]::FromBase64String($b64_1)
[System.IO.File]::WriteAllBytes($outFile1, $bytes1)
Write-Host "  OK  $outFile1" -ForegroundColor Green

# --- Spec 3 D1.6 — Kerberos Delegation Chain Map ---
$b64_2 = ""

$outFile2 = Join-Path $discoveryDir "Spec3-D1.6-Get-KerberosDelegationChainMap.ps1"
$bytes2 = [System.Convert]::FromBase64String($b64_2)
[System.IO.File]::WriteAllBytes($outFile2, $bytes2)
Write-Host "  OK  $outFile2" -ForegroundColor Green

Write-Host "`nAll D1.6 scripts written. Now run:" -ForegroundColor Cyan
Write-Host "  cd C:\Users\whale\git\uiao" -ForegroundColor White
Write-Host "  git add tools/discovery/Spec*-D1.6-*.ps1" -ForegroundColor White
Write-Host '  git commit -m "feat(discovery): add D1.6 scripts — BitLocker/LAPS, Worker Type Taxonomy, Delegation Chain Map' -ForegroundColor White
Write-Host "" -ForegroundColor White
Write-Host "    - Spec1-D1.6: BitLocker & LAPS State Assessment (4-pass, migration readiness)" -ForegroundColor White
Write-Host "    - Spec2-D1.6: Worker Type Taxonomy (6 canonical types, JML lifecycle, license SKUs)" -ForegroundColor White
Write-Host '    - Spec3-D1.6: Kerberos Delegation Chain Map (D1.4+D1.5 correlation, multi-hop/circular detection)"' -ForegroundColor White
Write-Host "  git push origin main" -ForegroundColor White
